starterFiles.content:
class SavingsGoal:
    def __init__(self, name, target):
        self.name = name
        self.target = target
        self.saved = 0

    def deposit(self, amount):
        if amount > 0:
            self.saved += amount
        return self.saved

    def percent_complete(self):
        return int((self.saved / self.target) * 100)

